1	/**
2	 * Astrolabe — public types.
3	 *
4	 * PlanDoc, ScopeItem, Decision, and supporting types for the brief-to-spec
5	 * planning pipeline.
6	 */
7	
8	// ── Plan status ──────────────────────────────────────────────────────
9	
10	export type PlanStatus = 'reading' | 'analyzing' | 'reviewing' | 'writing' | 'completed' | 'failed';
11	
12	// ── Documents ────────────────────────────────────────────────────────
13	
14	export interface PlanDoc {
15	  [key: string]: unknown;
16	  /** The brief writ ID — primary key. */
17	  id: string;
18	  /** The codex this plan targets. */
19	  codex: string;
20	  /** Planning status. */
21	  status: PlanStatus;
22	
23	  // ── Reader output ───────────────────────────────────────────
24	  /** Codebase inventory: affected files, types, interfaces, patterns. */
25	  inventory?: string;
26	
27	  // ── Analyst output ──────────────────────────────────────────
28	  /** Analyst observations: refactoring opportunities, risks, conventions. */
29	  observations?: string;
30	  /** Scope items: what's in and what's out. */
31	  scope?: ScopeItem[];
32	  /** Architectural/design decisions with options and analysis. */
33	  decisions?: Decision[];
34	
35	  // ── Spec-writer output ──────────────────────────────────────
36	  /** The generated specification. */
37	  spec?: string;
38	  /** The writ ID of the generated mandate (or configured type). */
39	  generatedWritId?: string;
40	
41	  createdAt: string;
42	  updatedAt: string;
43	}
44	
45	export interface ScopeItem {
46	  id: string;
47	  description: string;
48	  rationale: string;
49	  included: boolean;
50	}
51	
52	export interface DecisionAnalysis {
53	  /** Decision domain: product-level, API contract, or internal implementation. */
54	  category?: 'product' | 'api' | 'implementation';
55	  /** Whether the choice is externally visible to consumers of the feature/API. */
56	  observable?: boolean;
57	  /** How clearly the codebase and brief dictate the answer. */
58	  confidence?: 'low' | 'medium' | 'high';
59	  /** How much a consumer would notice if a different option were picked. */
60	  stakes?: 'low' | 'high';
61	}
62	
63	export interface Decision {
64	  id: string;
65	  scope: string[];
